# Resolvers
def resolve_user(_, info, id):
    current_user = getattr(info.context, 'current_user', None)
    user = next((u for u in users if u['id'] == id), None)
    if not user:
        return None
    return user

def resolve_users(_, info):
    current_user = getattr(info.context, 'current_user', None)
    return users

def resolve_me(_, info):
    current_user = getattr(info.context, 'current_user', None)
    if not current_user:
        return None
    return current_user

